        graph.add_vertex(key)

    # Add an edge between two tasks if one is dependent on another
    for key, value in dependencies.items():
        for v in value:
            graph.add_edge(v, key)

    return graph.topological_sort()

def topological_sort(self):
    # Create an empty list to hold the sorted elements
    result = []

    # Iterate through the vertices in topological order
    for vertex in self._vertices:
        if not vertex.visited:
            self._topological_sort_helper(vertex, result)

    return result

